    {'id': 'P3', 'title': 'Alpine Trek Poles',  'description': 'Summit carbon poles',        'badge': 'sponsored', 'popularity': 5},
    {'id': 'P4', 'title': 'Alpine Trek Tent',   'description': 'Alpine Trek shelter system', 'badge': 'none',      'popularity': 99},
    {'id': 'P5', 'title': 'Alpine Trek Gloves', 'description': 'Summit winter gloves',       'badge': 'sponsored', 'popularity': 40},
    {'id': 'P6', 'title': 'Alpine Trek Socks',  'description': 'Merino wool socks',          'badge': 'featured',  'popularity': 100},
]
print("INDEX", client.collections['test_cat'].documents.import_(docs, {'action': 'upsert'}))

# Test 1: Default search (no text_match_type)
q = {
    'q': 'Alpine',
    'query_by': 'title,description',
}
print("\n=== Default sort ===")
r = client.collections['test_cat'].documents.search(q)
for h in r['hits']:
    print(f"  {h['document']['id']}  text_match={h.get('text_match','-')}  text_match_info={h.get('text_match_info','-')}")

# Test 2: text_match_type=count (newer mode)
for tmt in ['count', 'max_score', 'sum_score', 'avg_score', 'bool', 'boolean', 'none']:
    try:
        q = {
            'q': 'Alpine',
            'query_by': 'title,description',
            'sort_by': '_text_match:desc',
            'text_match_type': tmt,
        }
        r = client.collections['test_cat'].documents.search(q)
        print(f"\n=== text_match_type={tmt}, sort_by=_text_match:desc ===")
        for h in r['hits']:
            tmi = h.get('text_match_info', {})
            print(f"  {h['document']['id']}  text_match_info={tmi}")
    except Exception as e:
        print(f"text_match_type={tmt} ERROR: {e}")

# Test 3: Eval syntax
print("\n=== _eval test ===")
try:
    r = client.collections['test_cat'].documents.search({
        'q': 'Alpine',
        'query_by': 'title,description',
        'sort_by': '_eval(badge:sponsored:3, badge:featured:2, badge:none:1):desc,_text_match:desc,popularity:desc',
    })
    for h in r['hits']:
        print(f"  {h['document']['id']} badge={h['document']['badge']} pop={h['document']['popularity']}")
except Exception as e:
    print("ERROR:", e)
